#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include "cJSON.h"
#include "lodepng.h"

class MnistModel {
private:
    std::vector<std::vector<float>> input_weight;
    std::vector<float> input_bias;
    std::vector<std::vector<float>> hidden_weight;
    std::vector<float> hidden_bias;
    std::vector<std::vector<float>> output_weight;
    std::vector<float> output_bias;

public:
    bool loadWeights(const std::string& filename) {
        FILE* file = fopen(filename.c_str(), "r");
        if (!file) return false;

        fseek(file, 0, SEEK_END);
        long length = ftell(file);
        fseek(file, 0, SEEK_SET);

        std::string buffer(length, '\0');
        fread(&buffer[0], 1, length, file);
        fclose(file);

        cJSON* root = cJSON_Parse(buffer.c_str());
        if (!root) return false;

        cJSON* weights = cJSON_GetObjectItem(root, "weights");
        if (!weights) {
            cJSON_Delete(root);
            return false;
        }

        // Load input layer weights
        cJSON* input_layer = cJSON_GetObjectItem(weights, "input_layer");
        loadLayerWeights(input_layer, input_weight, input_bias);

        // Load hidden layer weights
        cJSON* hidden_layer = cJSON_GetObjectItem(weights, "hidden_layer");
        loadLayerWeights(hidden_layer, hidden_weight, hidden_bias);

        // Load output layer weights
        cJSON* output_layer = cJSON_GetObjectItem(weights, "output_layer");
        loadLayerWeights(output_layer, output_weight, output_bias);

        cJSON_Delete(root);
        return true;
    }

    void loadLayerWeights(cJSON* layer, std::vector<std::vector<float>>& weight, std::vector<float>& bias) {
        cJSON* weight_json = cJSON_GetObjectItem(layer, "weight");
        cJSON* bias_json = cJSON_GetObjectItem(layer, "bias");

        int rows = cJSON_GetArraySize(weight_json);
        int cols = cJSON_GetArraySize(cJSON_GetArrayItem(weight_json, 0));

        weight.resize(rows, std::vector<float>(cols));
        for (int i = 0; i < rows; i++) {
            cJSON* row = cJSON_GetArrayItem(weight_json, i);
            for (int j = 0; j < cols; j++) {
                weight[i][j] = cJSON_GetArrayItem(row, j)->valuedouble;
            }
        }

        bias.resize(cJSON_GetArraySize(bias_json));
        for (int i = 0; i < bias.size(); i++) {
            bias[i] = cJSON_GetArrayItem(bias_json, i)->valuedouble;
        }
    }

    std::vector<float> relu(const std::vector<float>& x) {
        std::vector<float> result(x.size());
        for (int i = 0; i < x.size(); i++) {
            result[i] = std::max(0.0f, x[i]);
        }
        return result;
    }

    std::vector<float> linear(const std::vector<float>& x, const std::vector<std::vector<float>>& weight, const std::vector<float>& bias) {
        std::vector<float> result(bias.size());
        for (int i = 0; i < bias.size(); i++) {
            result[i] = bias[i];
            for (int j = 0; j < x.size(); j++) {
                result[i] += x[j] * weight[j][i];
            }
        }
        return result;
    }

    int predict(const std::vector<float>& x) {
        auto hidden1 = linear(x, input_weight, input_bias);
        hidden1 = relu(hidden1);

        auto hidden2 = linear(hidden1, hidden_weight, hidden_bias);
        hidden2 = relu(hidden2);

        auto output = linear(hidden2, output_weight, output_bias);

        return std::max_element(output.begin(), output.end()) - output.begin();
    }
};

std::vector<float> loadAndPreprocessImage(const std::string& filename) {
    std::vector<unsigned char> image;
    unsigned width, height;

    unsigned error = lodepng::decode(image, width, height, filename);
    if (error) {
        std::cerr << "Error loading image: " << lodepng_error_text(error) << std::endl;
        return {};
    }

    // Convert to grayscale and normalize to [0, 1]
    std::vector<float> result(width * height);
    for (int i = 0; i < width * height; i++) {
        // Assuming RGB or RGBA, take the first channel (R) as grayscale
        float pixel = image[i * 4] / 255.0f;
        result[i] = pixel;
    }

    return result;
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " weights.json image.png" << std::endl;
        return 1;
    }

    MnistModel model;
    if (!model.loadWeights(argv[1])) {
        std::cerr << "Error loading weights" << std::endl;
        return 1;
    }

    std::vector<float> image_data = loadAndPreprocessImage(argv[2]);
    if (image_data.empty()) {
        std::cerr << "Error loading image" << std::endl;
        return 1;
    }

    int prediction = model.predict(image_data);
    std::cout << prediction << std::endl;

    return 0;
}
